                alt="Капча"
                className="rounded-lg border border-[var(--border)] max-w-full"
                style={{ imageRendering: "crisp-edges" }}
              />
            </div>
          )}

          <div className="flex items-center gap-3">
            <input
              ref={captchaRef}
              type="text"
              value={captchaText}
