  const loaded = new Set(
    db.prepare("SELECT report_id FROM reports").all().map((r) => r.report_id)
  );
  console.log(`Уже загружено: ${loaded.size} отчётов`);

  // Группируем по периоду (type1 + type2)
  const periods = {};
  for (const r of wbReports) {
    const key = r.dateFrom?.slice(0, 10);
    if (!key) continue;
    if (!periods[key]) periods[key] = [];
    periods[key].push(r);
  }

  let newCount = 0;
  for (const [periodFrom, reports] of Object.entries(periods).sort()) {
    const allLoaded = reports.every((r) => loaded.has(r.id));
    if (allLoaded) continue;

    // Новый период — скачиваем
    const periodTo = reports[0].dateTo?.slice(0, 10);
    console.log(`\n📥 Новый период: ${periodFrom} — ${periodTo}`);

    for (const report of reports) {
      if (loaded.has(report.id)) {
        console.log(`  type=${report.type}: уже загружен (#${report.id})`);
        continue;
      }

      console.log(`  type=${report.type}: скачиваю (#${report.id}, ${report.detailsCount} строк)...`);
      try {
        const xlsxBuf = await downloadExcel(headers, report.id);
        if (!xlsxBuf) continue;

        const rowsLoaded = loadExcelToDB(db, xlsxBuf, report.id, report.type, periodFrom, periodTo);
        console.log(`  ✅ type=${report.type}: загружено ${rowsLoaded} строк`);
        newCount++;
      } catch (e) {
        console.log(`  ❌ type=${report.type}: ${e.message}`);
      }
    }
  }

  // Пересчёт buyout_rates в finance.db
  if (newCount > 0) {
    try {
      const financeDbPath = path.join(__dirname, "..", "data", "finance.db");
      const fdb = new Database(financeDbPath);
      fdb.exec(`CREATE TABLE IF NOT EXISTS buyout_rates (
        article_wb TEXT PRIMARY KEY,
        orders INTEGER,
        buyouts INTEGER,
        buyout_rate REAL,
        updated_at TEXT DEFAULT (datetime('now'))
      )`);
      fdb.exec(`CREATE TABLE IF NOT EXISTS weekly_buyout_stats (
        period_from TEXT,
        period_to TEXT,
        orders INTEGER,
        buyouts INTEGER,
        returns INTEGER,
        return_rate REAL,
        PRIMARY KEY(period_from, period_to)
      )`);
      fdb.exec("DELETE FROM buyout_rates");
      fdb.exec("DELETE FROM weekly_buyout_stats");
      const rows = db.prepare(`
        SELECT nm_id,
          COUNT(DISTINCT CASE WHEN supplier_oper_name = 'Логистика' THEN srid END) as orders,
          COUNT(DISTINCT CASE WHEN supplier_oper_name = 'Продажа' THEN srid END) as buyouts
        FROM weekly_rows
        WHERE supplier_oper_name IN ('Логистика', 'Продажа') AND nm_id != ''
        GROUP BY nm_id
        HAVING orders >= 30
      `).all();
      const ins = fdb.prepare("INSERT INTO buyout_rates (article_wb, orders, buyouts, buyout_rate) VALUES (?, ?, ?, ?)");
      fdb.transaction(() => {
        for (const r of rows) {
          ins.run(r.nm_id, r.orders, r.buyouts, r.orders > 0 ? r.buyouts / r.orders : 0);
        }
      })();
      fdb.close();
      // Weekly buyout stats
      const weeklyRows = db.prepare(`
        SELECT period_from, period_to,
          COUNT(DISTINCT CASE WHEN supplier_oper_name = 'Логистика' THEN srid END) as orders,
          COUNT(DISTINCT CASE WHEN supplier_oper_name = 'Продажа' THEN srid END) as buyouts
        FROM weekly_rows
        WHERE supplier_oper_name IN ('Логистика', 'Продажа')
        GROUP BY period_from, period_to
      `).all();
      const insW = fdb.prepare("INSERT INTO weekly_buyout_stats VALUES (?, ?, ?, ?, ?, ?)");
      fdb.transaction(() => {
        for (const w of weeklyRows) {
          const returns = w.orders - w.buyouts;
          insW.run(w.period_from, w.period_to, w.orders, w.buyouts, returns, w.orders > 0 ? returns / w.orders : 0);
        }
      })();
      console.log(`✅ buyout_rates обновлены: ${rows.length} артикулов, ${weeklyRows.length} недель`);
    } catch (e) {
      console.log(`⚠️ buyout_rates: ${e.message}`);
    }
  }

  // WAL checkpoint — сбрасываем WAL чтобы не блокировать readonly соединения
  if (newCount > 0) {
    try { db.pragma("wal_checkpoint(TRUNCATE)"); } catch { /* ignore */ }
  }

  // Итог
  const total = db.prepare("SELECT COUNT(*) as c FROM weekly_rows").get();
  const reportsList = db.prepare("SELECT * FROM reports ORDER BY period_from DESC").all();

  console.log(`\n════════════════════════════`);
  if (newCount > 0) {
    console.log(`✅ Загружено новых: ${newCount}`);
  } else {
    console.log(`ℹ️ Новых отчётов нет`);
  }
  console.log(`Всего в базе: ${total.c} строк, ${reportsList.length} отчётов`);
  reportsList.slice(0, 6).forEach((r) =>
    console.log(`  #${r.report_id} type=${r.report_type}: ${r.period_from}—${r.period_to} (${r.rows_count} строк)`)
  );

  db.close();

  // Код выхода: 0 = есть новые или нет новых, 1 = ошибка
  process.exit(0);
}

main().catch((e) => {
  console.error("❌ Критическая ошибка:", e.message);
  process.exit(1);
});

#!/usr/bin/env python3
"""
VPS Watchdog — мониторинг сервисов на VPS.
Проверяет PM2 (website), cron-задачи (по логам), отправляет алерты в Telegram.

Запуск: каждые 5 мин через cron
"""

import json
import os
import sys
import subprocess
import fcntl
from pathlib import Path
from datetime import datetime, timedelta

# ─── Config ──────────────────────────────────────────────────

PROJECT_DIR = Path(__file__).parent.parent
DATA_DIR = PROJECT_DIR / "data"
STATE_PATH = DATA_DIR / "vps-watchdog-state.json"
LOCK_PATH = Path("/tmp/vps-watchdog.lock")
LOG_PATH = DATA_DIR / "watchdog.log"
NOTIFY_SH = PROJECT_DIR / "scripts" / "notify.sh"

# Cron tasks and their expected intervals (minutes)
CRON_TASKS = {
    "daily-sync": {"log": DATA_DIR / "daily-sync.log", "max_age_min": 120, "name": "Daily Sync"},
    "reviews-sync": {"log": DATA_DIR / "reviews-sync.log", "max_age_min": 15, "name": "Reviews Sync"},
    "reviews-complaints": {"log": DATA_DIR / "reviews-complaints.log", "max_age_min": 45, "name": "Reviews Complaints"},
    "shipment-sync": {"log": DATA_DIR / "shipment-sync.log", "max_age_min": 90, "name": "Shipment Sync"},
    # Weekly-sync запускается Пн-Ср 10-23 МСК. В остальные дни и часы проверка пропускается.
    "weekly-sync": {"log": DATA_DIR / "weekly-sync.log", "max_age_min": 90, "name": "Weekly Sync", "only_dow_msk": [1, 2, 3], "only_hours_msk": list(range(10, 24))},
    # Paid-storage-sync гоняется 02:00 МСК. Проверка — только в окне 03-23 МСК (после запуска).
    "paid-storage-sync": {"log": DATA_DIR / "paid-storage-sync.log", "max_age_min": 1440, "name": "Paid Storage Sync", "only_hours_msk": list(range(3, 24))},
}

# ─── Logging ─────────────────────────────────────────────────

def log(msg):
    line = f"[{datetime.now().isoformat(timespec='seconds')}] {msg}"
    try:
        LOG_PATH.parent.mkdir(parents=True, exist_ok=True)
        with open(LOG_PATH, "a") as f:
            f.write(line + "\n")
    except Exception:
        pass


# ─── Lock ────────────────────────────────────────────────────

def acquire_lock():
    try:
        fp = open(LOCK_PATH, "w")
        fcntl.flock(fp, fcntl.LOCK_EX | fcntl.LOCK_NB)
        return fp
    except (IOError, OSError):
        return None


# ─── State ───────────────────────────────────────────────────

def load_state():
    if STATE_PATH.exists():
        try:
            return json.loads(STATE_PATH.read_text())
        except Exception:
            pass
    return {}


def save_state(state):
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    STATE_PATH.write_text(json.dumps(state, indent=2, ensure_ascii=False))


# ─── Telegram ────────────────────────────────────────────────

LEVEL_EMOJI = {"INFO": "\u2705", "WARNING": "\u26a0\ufe0f", "CRITICAL": "\U0001f6a8"}

def send_telegram(level, message):
    """Отправка через notify.sh (SSH-туннель через claude-cli → Germany)."""
    emoji = LEVEL_EMOJI.get(level, "\u2139\ufe0f")
    # Конвертируем простой Markdown *bold* → HTML <b>bold</b> (notify.sh использует HTML)
    import re as _re
    html_message = _re.sub(r"\*([^*]+)\*", r"<b>\1</b>", message)
    text = f"{emoji} <b>VPS Watchdog — {level}</b>\n\n{html_message}"
    try:
        result = subprocess.run(
            ["bash", str(NOTIFY_SH), text],
            capture_output=True, text=True, timeout=30,
        )
        if result.returncode == 0:
            log(f"  Telegram [{level}] sent")
        else:
            log(f"  Telegram error: rc={result.returncode}, {result.stderr[:200]}")
    except Exception as e:
        log(f"  Telegram error: {e}")


# ─── Checks ──────────────────────────────────────────────────

def check_pm2():
    """Check PM2 mphub process."""
    try:
        result = subprocess.run(
            ["sudo", "pm2", "jlist"],
            capture_output=True, text=True, timeout=10,
        )
        procs = json.loads(result.stdout)
        for p in procs:
            if p["name"] == "mphub":
                status = p["pm2_env"]["status"]
                pid = p["pid"]
                restarts = p["pm2_env"]["restart_time"]
                uptime = p["pm2_env"].get("pm_uptime", 0)
                return {
                    "status": status,
                    "pid": pid,
                    "restarts": restarts,
                    "uptime_ms": int(datetime.now().timestamp() * 1000) - uptime if uptime else 0,
                }
        return {"status": "not_found", "pid": 0, "restarts": 0, "uptime_ms": 0}
    except Exception as e:
        return {"status": "error", "pid": 0, "restarts": 0, "error": str(e)}


def check_http():
    """Check if website responds."""
    try:
        result = subprocess.run(
            ["curl", "-s", "-o", "/dev/null", "-w", "%{http_code}", "--max-time", "10", "http://localhost:80"],
            capture_output=True, text=True, timeout=15,
        )
        code = result.stdout.strip()
        return {"ok": code in ("200", "301", "302", "307"), "code": code}
    except Exception as e:
        return {"ok": False, "code": "000", "error": str(e)}


def check_cron_task(task_id, config):
    """Check if cron task ran recently by log file modification time.
    Если у задачи ограничено расписание (only_dow_msk / only_hours_msk),
    вне этого окна проверка пропускается."""
    log_path = config["log"]
    max_age = config["max_age_min"]

    if not log_path.exists():
        return {"ok": False, "reason": "no log file"}

    mtime = datetime.fromtimestamp(log_path.stat().st_mtime)
    age_min = (datetime.now() - mtime).total_seconds() / 60

    # Расписание-aware check: если задача запускается только в определённые
    # дни/часы (МСК), вне окна — skip.
    now_utc = datetime.utcnow()
    msk_hour = (now_utc.hour + 3) % 24
    # ISO weekday: Пн=1..Вс=7
    msk_dow = (now_utc.weekday() + 1) if (now_utc.hour + 3) < 24 else ((now_utc.weekday() + 1) % 7) + 1

    only_dow = config.get("only_dow_msk")
    only_hours = config.get("only_hours_msk")
    if only_dow and msk_dow not in only_dow:
        return {"ok": True, "age_min": round(age_min), "note": f"out-of-schedule (dow={msk_dow})"}
    if only_hours and msk_hour not in only_hours:
        return {"ok": True, "age_min": round(age_min), "note": f"out-of-schedule (hour={msk_hour})"}

    return {"ok": age_min <= max_age, "age_min": round(age_min)}


def check_disk():
    """Check disk usage."""
    try:
        result = subprocess.run(
            ["df", "--output=pcent", "/"],
            capture_output=True, text=True, timeout=5,
        )
        pct = int(result.stdout.strip().split("\n")[-1].strip().replace("%", ""))
        return {"ok": pct < 90, "percent": pct}
    except Exception:
        return {"ok": True, "percent": 0}


def restart_pm2():
    """Restart PM2 mphub process."""
    try:
        log("  Restarting PM2 mphub...")
        result = subprocess.run(
            ["sudo", "pm2", "restart", "mphub"],
            capture_output=True, text=True, timeout=30,
        )
        time.sleep(5)
        check = check_pm2()
        ok = check["status"] == "online"
        log(f"  Restart {'OK' if ok else 'FAILED'}")
        return ok
    except Exception as e:
        log(f"  Restart error: {e}")
        return False


# ─── Main ────────────────────────────────────────────────────

import time

def main():
    log("=== VPS Watchdog started ===")

    state = load_state()
    alerts = []

    # 1. Check PM2
    pm2 = check_pm2()
    log(f"PM2: {pm2['status']} (pid={pm2['pid']}, restarts={pm2['restarts']})")

    if pm2["status"] != "online":
        log(f"ALERT: PM2 mphub is {pm2['status']}")
        prev_restarts = state.get("pm2_restart_count", 0)
        if prev_restarts < 3:
            ok = restart_pm2()
            state["pm2_restart_count"] = prev_restarts + 1
            if ok:
                alerts.append(("INFO", "*MpHub Website* — перезапущен и работает."))
            else:
                alerts.append(("CRITICAL", f"*MpHub Website* — не удалось перезапустить! Status: {pm2['status']}"))
        else:
            alerts.append(("CRITICAL", f"*MpHub Website* — упал {prev_restarts}x. Требуется ручное вмешательство."))
    else:
        if state.get("pm2_restart_count", 0) > 0:
            state["pm2_restart_count"] = 0

    # 2. Check HTTP
    http = check_http()
    log(f"HTTP: {http['code']} ({'OK' if http['ok'] else 'FAIL'})")

    if not http["ok"] and pm2["status"] == "online":
        alerts.append(("WARNING", f"*MpHub Website* — PM2 online, но HTTP не отвечает (code={http['code']})."))

    # 3. Check cron tasks
    for task_id, config in CRON_TASKS.items():
        result = check_cron_task(task_id, config)
        if not result["ok"]:
            age = result.get("age_min", "?")
            reason = result.get("reason", f"последний запуск {age} мин назад (макс {config['max_age_min']})")
            alert_key = f"cron_{task_id}_alerted"
            if not state.get(alert_key):
                alerts.append(("WARNING", f"*{config['name']}* — не запускался вовремя. {reason}"))
                state[alert_key] = datetime.now().isoformat()
        else:
            alert_key = f"cron_{task_id}_alerted"
            if state.get(alert_key):
                del state[alert_key]

    # 4. Check disk
    disk = check_disk()
    log(f"Disk: {disk['percent']}%")
    if not disk["ok"]:
        alerts.append(("WARNING", f"*Диск* — заполнен на {disk['percent']}%."))

    # 5. Send alerts
    for level, msg in alerts:
        send_telegram(level, msg)

    state["last_run"] = datetime.now().isoformat()
    save_state(state)

    log(f"Alerts: {len(alerts)} | === Watchdog done ===\n")


if __name__ == "__main__":
    lock = acquire_lock()
    if not lock:
        sys.exit(0)
    try:
        main()
    finally:
        lock.close()
        try:
            LOCK_PATH.unlink()
        except Exception:
            pass

#!/usr/bin/env node
/**
 * e2e-test.js — End-to-end тестирование /shipment через Puppeteer
 *
 * Запуск: node scripts/e2e-test.js [--screenshots-dir /path]
 *
 * Что делает:
 *  1. Открывает /shipment
 *  2. Проверяет все вкладки (Расчёт, Товары, Загрузка данных, Настройки отгрузки)
 *  3. Проверяет режимы V1/V2/V3
 *  4. Проверяет переключение настроек (выкуп, регионы)
 *  5. Проверяет инварианты (значения >= 0, суммы, корректность данных)
 *  6. Делает скриншоты каждого шага
 *  7. Выводит отчёт: ✅/❌ по каждой проверке
 */

const puppeteer = require("puppeteer");
const fs = require("fs");
const path = require("path");

const PROFILE_DIR = "/Users/octopus/.puppeteer-profile";
const BASE_URL = "http://localhost:3000";
const DEFAULT_SCREENSHOTS_DIR = "/Users/octopus/.openclaw/agents/chuck/agent/test-results";

// Parse args
const args = process.argv.slice(2);
const screenshotsDir = args.includes("--screenshots-dir")
  ? args[args.indexOf("--screenshots-dir") + 1]
  : DEFAULT_SCREENSHOTS_DIR;

// Test results
const results = [];
let screenshotIndex = 0;

function pass(name, details = "") {
  results.push({ status: "PASS", name, details });
  console.log(`  ✅ ${name}${details ? ` — ${details}` : ""}`);
}

function fail(name, details = "") {
  results.push({ status: "FAIL", name, details });
  console.log(`  ❌ ${name}${details ? ` — ${details}` : ""}`);
}

async function screenshot(page, label) {
  screenshotIndex++;
  const filename = `${String(screenshotIndex).padStart(2, "0")}-${label.replace(/[^a-zA-Z0-9а-яА-Я-]/g, "_")}.png`;
  const filepath = path.join(screenshotsDir, filename);
  await page.screenshot({ path: filepath, fullPage: false });
  return filepath;
}

async function clickButton(page, text) {
  const clicked = await page.evaluate((t) => {
    for (const b of document.querySelectorAll("button")) {
      if (b.textContent && b.textContent.trim().includes(t)) {
        b.click();
        return true;
      }
    }
    return false;
  }, text);
  if (clicked) await new Promise((r) => setTimeout(r, 1500));
  return clicked;
}

async function getPageText(page) {
  return page.evaluate(() => document.body.innerText);
}

async function getTableNumbers(page, selector = "table.data-table") {
  return page.evaluate((sel) => {
    const table = document.querySelector(sel);
    if (!table) return [];
    const cells = Array.from(table.querySelectorAll("td.num, td[class*='num']"));
    return cells.map((c) => {
      const text = c.textContent.trim().replace(/\s/g, "").replace("—", "");
      return text === "" ? null : parseFloat(text.replace(",", "."));
    }).filter((n) => n !== null);
  }, selector);
}

async function countTableRows(page) {
  return page.evaluate(() => {
    const table = document.querySelector("table.data-table");
    if (!table) return 0;
    return table.querySelectorAll("tbody tr").length;
  });
}

async function getCardValues(page) {
  return page.evaluate(() => {
    const cards = Array.from(document.querySelectorAll("[class*='grid'] > div"));
    return cards.map((c) => ({
      label: (c.querySelector("[class*='text-muted']") || {}).textContent || "",
      value: (c.querySelector("[class*='font-bold']") || {}).textContent || "",
    }));
  });
}

// ═══════════════════════════════════════════════════
// ТЕСТЫ
// ═══════════════════════════════════════════════════

async function testPageLoad(page) {
  console.log("\n📋 ГРУППА 1: Загрузка страницы");
  await page.goto(BASE_URL + "/shipment", { waitUntil: "networkidle2", timeout: 20000 });
  await new Promise((r) => setTimeout(r, 2000));

  const text = await getPageText(page);

  // 1.1 Страница загрузилась
  if (text.includes("Расчёт отгрузки")) {
    pass("Страница /shipment загрузилась");
  } else {
    fail("Страница /shipment не загрузилась");
    return false;
  }

  // 1.2 Есть данные
  if (!text.includes("Нет данных для расчёта")) {
    pass("Данные загружены (не пустая страница)");
  } else {
    fail("Нет данных — загрузите через UploadTab сначала");
    return false;
  }

  // 1.3 Все 4 вкладки присутствуют
  const tabs = ["Расчёт", "Товары", "Загрузка данных", "Настройки отгрузки"];
  for (const tab of tabs) {
    if (text.includes(tab)) {
      pass(`Вкладка «${tab}» присутствует`);
    } else {
      fail(`Вкладка «${tab}» отсутствует`);
    }
  }

  await screenshot(page, "01-page-loaded");
  return true;
}

async function testCalcModes(page) {
  console.log("\n📋 ГРУППА 2: Режимы расчёта V1/V2/V3");

  // Убедимся что мы на вкладке Расчёт
  await clickButton(page, "Расчёт");
  await new Promise((r) => setTimeout(r, 1000));

  // 2.1 V3 по умолчанию — проверяем карточки Smart
  const textV3 = await getPageText(page);
  if (textV3.includes("Коробов (Smart)") || textV3.includes("Smart")) {
    pass("V3 — карточки Smart видны (режим по умолчанию)");
  } else {
    fail("V3 — карточки Smart НЕ видны");
  }

  // Проверяем summary карточки V3
  const hasBalance = textV3.includes("Баланс склада");
  const hasDemand = textV3.includes("Переизбыток") || textV3.includes("Дефицит");
  const hasOnWB = textV3.includes("Остаток на складе WB");
  if (hasBalance && hasDemand && hasOnWB) {
    pass("V3 — все 4 карточки видны (Остаток/Переизбыток/К отгрузке/Баланс)");
  } else {
    fail("V3 — не все карточки видны", `Баланс:${hasBalance} Потребность:${hasDemand} НаВБ:${hasOnWB}`);
  }

  await screenshot(page, "02-v3-default");

  // 2.2 Переключение на V1
  await clickButton(page, "V1 Стандарт");
  const textV1 = await getPageText(page);
  const v1HasBoxes = textV1.includes("Шт/кор") || textV1.includes("Коробки");
  if (!v1HasBoxes && textV1.includes("Нужно")) {
    pass("V1 — без коробок, столбец «Нужно» виден");
  } else if (!v1HasBoxes) {
    pass("V1 — без коробок");
  } else {
    fail("V1 — столбцы коробок присутствуют (не должны)");
  }
  await screenshot(page, "03-v1-standard");

  // 2.3 Переключение на V2
  await clickButton(page, "V2 Динамика");
  await new Promise((r) => setTimeout(r, 500));
  const textV2 = await getPageText(page);
  const textV2Lower = textV2.toLowerCase();
